function c(e){return e?e.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[횪찼창찾채책]/g,"a").replace(/[챔챕챗챘]/g,"e").replace(/[챙챠챤챦]/g,"i").replace(/[챵처척천철]/g,"o").replace(/[첫첬청체]/g,"u").replace(/[첵첼]/g,"y").replace(/[챰]/g,"n").replace(/[챌]/g,"c").replace(/[흹]/g,"oe").replace(/[챈]/g,"ae").replace(/[^a-z0-9]+/g,"-").replace(/^-+|-+$/g,"").replace(/-+/g,"-"):""}function g(e,r){const a=c(e),n=r.substring(0,8);return`/p/${a}-${n}`}function l(e,r){const a=g(e,r);return`${window.location.origin}${a}`}export{l as a,g};
